
; ──────────────────────────────────────────────────────────────
; Petmate9 Animation Player (C64) – RLE + Nibble Packed
; Generated by run_animation_player_test.js
; Frames: 60   Speed: 6 vblanks/frame
; ──────────────────────────────────────────────────────────────
!include "macros.asm"



!let irq_top_line  = 1
!let debug_build   = FALSE
!let ANIM_FRAMES   = 60
!let ANIM_SPEED    = 6
!let RLE_MARKER    = $fe

; Zero-page pointers used by decoders
!let zp_src        = $20
!let zp_dst        = $22
!let zp_remain     = $24
!let zp_rle_val    = $26

+basic_start(entry)

;--------------------------------------------------------------
; Entry point
;--------------------------------------------------------------
entry: {



    sei
    lda #$35
    sta $01
    +setup_irq(irq_top, irq_top_line)
    cli

    ; Charset
    lda #$15
    sta $d018

    ; Init animation state
    lda #0
    sta currentFrame
    lda #1
    sta delayCounter

    jsr show_frame

main_loop:
    lda frameCount
vsync_wait:
    cmp frameCount
    beq vsync_wait

    dec delayCounter
    bne main_loop

    ; Reset delay, advance frame
    lda #ANIM_SPEED
    sta delayCounter

    ldx currentFrame
    inx
    cpx #ANIM_FRAMES
    bne no_wrap
    ldx #0
no_wrap:
    stx currentFrame

    jsr show_frame
    jmp main_loop
}

;--------------------------------------------------------------
; show_frame – decode current frame to screen + color RAM
;--------------------------------------------------------------
show_frame: {
    ldx currentFrame

    ; Border & background
    lda frame_border,x
    sta $d020
    lda frame_bg,x
    sta $d021

    ; ── RLE decode screen data ──
    lda frame_scr_lo,x
    sta zp_src
    lda frame_scr_hi,x
    sta zp_src+1
    lda #<SCREEN
    sta zp_dst
    lda #>SCREEN
    sta zp_dst+1
    lda #$e8            ; 1000 = $03E8
    sta zp_remain
    lda #$03
    sta zp_remain+1
    jsr rle_decode

    ; ── Nibble decode color data ──
    ldx currentFrame
    lda frame_col_lo,x
    sta zp_src
    lda frame_col_hi,x
    sta zp_src+1
    lda #<COLOR
    sta zp_dst
    lda #>COLOR
    sta zp_dst+1
    lda #$f4            ; 500 = $01F4
    sta zp_remain
    lda #$01
    sta zp_remain+1
    jsr nibble_decode

    rts
}

;--------------------------------------------------------------
; rle_decode
;   zp_src    → compressed stream
;   zp_dst    → destination (e.g. screen RAM)
;   zp_remain → bytes remaining to PRODUCE
;
; Format: $FE,0       = literal $FE
;         $FE,cnt,val = repeat val cnt times
;         other       = literal byte
;--------------------------------------------------------------
rle_decode: {
    ldy #0

next:
    lda zp_remain
    ora zp_remain+1
    beq done

    ; Read source byte
    lda (zp_src),y
    inc zp_src
    bne src1
    inc zp_src+1
src1:
    cmp #RLE_MARKER
    beq escape

    ; ── literal byte ──
    sta (zp_dst),y
    inc zp_dst
    bne dst1
    inc zp_dst+1
dst1:
    lda zp_remain
    bne rem1
    dec zp_remain+1
rem1:
    dec zp_remain
    jmp next

escape:
    ; Read count
    lda (zp_src),y
    inc zp_src
    bne src2
    inc zp_src+1
src2:
    beq literal_fe       ; count == 0 → literal $FE

    ; ── run of count × value ──
    tax
    lda (zp_src),y
    inc zp_src
    bne src3
    inc zp_src+1
src3:
    sta zp_rle_val

fill:
    lda zp_rle_val
    sta (zp_dst),y
    inc zp_dst
    bne dst2
    inc zp_dst+1
dst2:
    lda zp_remain
    bne rem2
    dec zp_remain+1
rem2:
    dec zp_remain
    dex
    bne fill
    jmp next

literal_fe:
    lda #RLE_MARKER
    sta (zp_dst),y
    inc zp_dst
    bne dst3
    inc zp_dst+1
dst3:
    lda zp_remain
    bne rem3
    dec zp_remain+1
rem3:
    dec zp_remain
    jmp next

done:
    rts
}

;--------------------------------------------------------------
; nibble_decode
;   zp_src    → nibble-packed stream
;   zp_dst    → destination (e.g. color RAM)
;   zp_remain → PACKED bytes to read (each produces 2 outputs)
;--------------------------------------------------------------
nibble_decode: {
    ldy #0

next:
    lda zp_remain
    ora zp_remain+1
    beq done

    ; Read packed byte
    lda (zp_src),y
    inc zp_src
    bne src1
    inc zp_src+1
src1:
    pha

    ; High nibble → first color
    lsr
    lsr
    lsr
    lsr
    sta (zp_dst),y
    inc zp_dst
    bne dst1
    inc zp_dst+1
dst1:

    ; Low nibble → second color
    pla
    and #$0f
    sta (zp_dst),y
    inc zp_dst
    bne dst2
    inc zp_dst+1
dst2:

    ; Decrement packed-byte counter
    lda zp_remain
    bne rem1
    dec zp_remain+1
rem1:
    dec zp_remain
    jmp next

done:
    rts
}

;--------------------------------------------------------------
; Raster IRQ
;--------------------------------------------------------------
irq_top: {
    +irq_start(end)
    inc frameCount

!if (debug_build) {
    inc $d020
}



!if (debug_build) {
    dec $d020
}

    +irq_end(irq_top, irq_top_line)
end:
}

